const TRANS: Record<string, Record<string, string>> = { en: EN, ...G1, ...G2, ...G3, ...G4 };

function setPath(root: any, dotted: string, value: string) {
  const parts = dotted.split(".");
  let cur = root;
  for (let i = 0; i < parts.length - 1; i++) {
    const p = parts[i];
    if (cur[p] == null) cur[p] = {};
    cur = cur[p];
  }
  cur[parts[parts.length - 1]] = value;
}

let files = 0;
for (const loc of LOCALES) {
  const t = TRANS[loc];
  if (!t) throw new Error(`No translations for locale ${loc}`);
  const file = join(MSG_DIR, `${loc}.json`);
  const msg = JSON.parse(readFileSync(file, "utf8"));
  for (const p of VERBATIM_PATHS) setPath(msg, p, BRAND);
  for (const [sid, path] of Object.entries(PROSE_PATHS)) {
    const v = t[sid];
    if (v == null) throw new Error(`Missing ${sid} for ${loc}`);
    setPath(msg, path, v);
  }
  writeFileSync(file, JSON.stringify(msg, null, 2) + "\n", "utf8");
  files++;
}
console.log(`✓ Kitchen Order App rename applied to ${files} locale file(s).`);
